using Microsoft.AspNetCore.Mvc; using SchoolEnterprise.Helpers; using SchoolEnterprise.Models.Domain; using SchoolEnterprise.Repositories; using SchoolEnterprise.Services;
namespace SchoolEnterprise.Controllers; [RoleGuard("Admin","Secretary")] public class TeachersController(TeacherRepository repo, SequenceService seq):Controller{ public IActionResult Index()=>View(repo.GetAll()); [HttpGet] public IActionResult Create()=>View(); [HttpPost] public IActionResult Create(Teacher t){t.TeacherId=seq.Next("TeacherId"); repo.Add(t); return RedirectToAction(nameof(Index));} [HttpGet] public IActionResult Edit(int id)=>View(repo.GetById(id)); [HttpPost] public IActionResult Edit(Teacher t){repo.Update(t); return RedirectToAction(nameof(Index));} public IActionResult Delete(int id){repo.Delete(id); return RedirectToAction(nameof(Index));}}
